import React, { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '../components/ui/card';
import { Chart as ChartJS, ArcElement, Tooltip, Legend } from 'chart.js';
import { Pie } from 'react-chartjs-2';
import { motion } from 'framer-motion';

ChartJS.register(ArcElement, Tooltip, Legend);

const MetricsPage = () => {
  const [metrics, setMetrics] = useState({
    cpuUsage: 45,
    memoryUsage: 60,
    networkTraffic: 1200,
    errorRate: 0.5,
  });

  useEffect(() => {
    const interval = setInterval(() => {
      setMetrics(prev => ({
        ...prev,
        cpuUsage: (prev.cpuUsage + Math.random() * 10) % 100,
        memoryUsage: (prev.memoryUsage + Math.random() * 5) % 100,
      }));
    }, 2000);
    return () => clearInterval(interval);
  }, []);

  const data = {
    labels: ['CPU', 'Memory', 'Network', 'Errors'],
    datasets: [
      {
        label: 'Usage %',
        data: [metrics.cpuUsage, metrics.memoryUsage, metrics.networkTraffic / 100, metrics.errorRate * 100],
        backgroundColor: ['#FF6384', '#36A2EB', '#FFCE56', '#4BC0C0'],
      },
    ],
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{ duration: 0.5 }}
      className="p-4 dark:bg-gray-800 dark:text-white"
    >
      <h1 className="text-3xl font-bold mb-4">Performance Metrics Dashboard</h1>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <Card className="dark:border-gray-700">
          <CardHeader>
            <CardTitle>CPU Usage</CardTitle>
          </CardHeader>
          <CardContent>
            <Pie data={data} options={{ responsive: true }} />
          </CardContent>
        </Card>
        <Card className="dark:border-gray-700">
          <CardHeader>
            <CardTitle>Memory Usage</CardTitle>
          </CardHeader>
          <CardContent>
            <p>{metrics.memoryUsage}% used</p>
            <motion.div
              className="h-4 bg-blue-500"
              initial={{ width: 0 }}
              animate={{ width: `${metrics.memoryUsage}%` }}
              transition={{ duration: 1 }}
            />
          </CardContent>
        </Card>
        <Card className="dark:border-gray-700">
          <CardHeader>
            <CardTitle>Network Traffic (MB/s)</CardTitle>
          </CardHeader>
          <CardContent>
            <p>{metrics.networkTraffic} MB/s</p>
          </CardContent>
        </Card>
        <Card className="dark:border-gray-700">
          <CardHeader>
            <CardTitle>Error Rate</CardTitle>
          </CardHeader>
          <CardContent>
            <p>{metrics.errorRate}% errors</p>
          </CardContent>
        </Card>
      </div>
      <div className="mt-8">
        <h2 className="text-2xl">Animated Metrics Summary</h2>
        <motion.p
          animate={{ scale: [1, 1.1, 1] }}
          transition={{ duration: 2, repeat: Infinity }}
        >
          Real-time updates every 2 seconds!
        </motion.p>
      </div>
    </motion.div>
  );
};

export default MetricsPage;
```

